command:
const targets = [...(game.user.targets ?? [])];
if (!targets.length) return ui.notifications.warn(game.i18n.localize("op.macroNeedsTarget"));

const typeOptions = Object.entries(CONFIG.op?.dropdownDamageType ?? {})
	.map(([k, v]) => `<option value="${k}">${game.i18n.localize(v)}</option>`)
	.join("");
const content = `
	<div class="form-group"><label>${game.i18n.localize("op.macroDamageAmount")}</label><input type="number" name="amount" value="0" min="0" autofocus /></div>
	<div class="form-group"><label>${game.i18n.localize("op.macroDamageType")}</label><select name="damageType"><option value="">${game.i18n.localize("op.macroNoDamageType")}</option>${typeOptions}</select></div>
	<div class="form-group"><label>${game.i18n.localize("op.macroIgnoreRD")}</label><input type="checkbox" name="ignoreRD" /></div>
	<div class="form-group"><label>${game.i18n.localize("op.macroNonLethal")}</label><input type="checkbox" name="nonLethal" /></div>
`;

const input = await foundry.applications.api.DialogV2.prompt({
	window: { title: game.i18n.localize("op.macroQuickDamageTitle") },
	content,
	ok: {
		label: game.i18n.localize("op.macroApplyButton"),
		callback: (_event, button) => new FormDataExtended(button.form).object,
	},
});
if (!input || !input.amount || input.amount <= 0) return;

const opts = {
	damageType: input.damageType || undefined,
	ignoreRD: !!input.ignoreRD,
	nonLethal: !!input.nonLethal,
};

for (const token of targets) {
	const actor = token.actor;
	if (!actor) continue;
	const result = await actor.applyDamage(Number(input.amount), opts);
	const blocked = result.blocked > 0 ? game.i18n.format("op.macroBlockedDR", { blocked: result.blocked }) : "";
	ChatMessage.create({
		content: game.i18n.format("op.macroDamageApplied", { amount: input.amount, actor: actor.name, final: result.finalDamage, blocked }),
		speaker: ChatMessage.getSpeaker({ actor }),
	});
}
